import { useRef, useState } from "react";
import { motion } from "framer-motion";
import { SectionLabel, sectionTitle } from "./Skills";

export default function Contact({ contact }) {
  const [copied, setCopied] = useState(false);
  const magnetRefs = useRef([]);

  const items = [
    { icon: "✉", label: "Email", value: contact.email, href: `mailto:${contact.email}`, copy: true },
    { icon: "📞", label: "Phone", value: contact.phone, href: `tel:${contact.phone}` },
    { icon: "in", label: "LinkedIn", value: contact.linkedin, href: contact.linkedinUrl, external: true },
    { icon: "📍", label: "Location", value: contact.location, href: null },
  ];

  const handleCopy = (text) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleMouseMove = (e, i) => {
    const el = magnetRefs.current[i];
    if (!el) return;

    const r = el.getBoundingClientRect();
    const x = (e.clientX - r.left - r.width / 2) * 0.08;
    const y = (e.clientY - r.top - r.height / 2) * 0.08;

    el.style.transform = `translate(${x}px, ${y}px)`;
    el.style.setProperty("--x", `${e.clientX - r.left}px`);
    el.style.setProperty("--y", `${e.clientY - r.top}px`);
  };

  const resetMagnet = (i) => {
    const el = magnetRefs.current[i];
    if (el) el.style.transform = "translate(0,0)";
  };

  const container = {
    hidden: {},
    show: { transition: { staggerChildren: 0.1 } },
  };

  const fadeUp = {
    hidden: { opacity: 0, y: 30 },
    show: { opacity: 1, y: 0, transition: { duration: 0.5 } },
  };

  return (
    <>
      <style>{`
        /* ===== SECTION ===== */
        .contact-section {
          padding: clamp(2.5rem, 6vw, 5rem) clamp(1.25rem, 5vw, 4rem);
          width: 100%;
        }

        /* ===== HEADER (LEFT ALIGNED LIKE EXPERIENCE) ===== */
        .contact-header {
          max-width: 850px;
          margin-bottom: 1.25rem;
        }

        .contact-heading {
          margin-bottom: 0.75rem;
        }

        .contact-desc {
          color: var(--muted);
          font-size: clamp(0.85rem, 1.2vw, 0.95rem);
          line-height: 1.7;
          max-width: 850px;
        }

        /* ===== GRID WRAPPER (CENTERING MAGIC) ===== */
        .contact-grid-wrapper {
          display: flex;
          justify-content: center; /* ✅ PERFECT CENTER */
          width: 100%;
          margin-top: 1.5rem;
        }

        /* ===== GRID ===== */
        .contact-grid {
          display: grid;
          grid-template-columns: repeat(4, minmax(220px, 260px));
          gap: clamp(1rem, 2vw, 1.5rem);
          width: 100%;
          max-width: 1100px; /* ✅ controls perfect centering */
        }

        /* ===== RESPONSIVE GRID ===== */
        @media (max-width: 1100px) {
          .contact-grid {
            grid-template-columns: repeat(2, 1fr);
          }
        }

        @media (max-width: 600px) {
          .contact-grid {
            grid-template-columns: 1fr;
          }
        }

        /* ===== CARD ===== */
        .contact-card {
          background: var(--surface2);
          border: 1px solid var(--border);
          border-radius: var(--radius);
          padding: clamp(1.2rem, 3vw, 2rem);
          display: flex;
          flex-direction: column;
          gap: 8px;
          cursor: pointer;
          position: relative;
          transition: all 0.3s ease;
          overflow: hidden;
        }

        /* Glow */
        .contact-card::before {
          content: "";
          position: absolute;
          inset: 0;
          background: radial-gradient(circle at var(--x,50%) var(--y,50%), rgba(0,229,255,0.15), transparent 60%);
          opacity: 0;
          transition: 0.3s;
        }

        .contact-card:hover::before {
          opacity: 1;
        }

        .contact-card:hover {
          transform: translateY(-4px);
          border-color: var(--accent);
          box-shadow: 0 10px 30px rgba(0,229,255,0.25);
        }

        .contact-icon {
          font-size: 1.3rem;
        }

        .contact-lbl {
          font-size: 0.7rem;
          color: var(--muted);
          font-weight: 700;
          letter-spacing: 0.12em;
          text-transform: uppercase;
        }

        .contact-val {
          font-size: 0.9rem;
          color: var(--text);
          text-decoration: none;
        }

        .contact-val:hover {
          color: var(--accent);
        }

        .contact-val--copied {
          color: var(--accent);
        }

        /* ===== CTA ===== */
        .contact-cta-row {
          display: flex;
          justify-content: center;
          margin-top: 2.5rem;
        }

        .contact-cta {
          background: linear-gradient(135deg, var(--accent), var(--accent2));
          color: white;
          padding: 12px 30px;
          border-radius: 999px;
          text-decoration: none;
          font-weight: 700;
          transition: 0.3s;
        }

        .contact-cta:hover {
          transform: scale(1.05);
        }

        /* ===== FOOTER ===== */
        .contact-footer {
          text-align: center;
          margin-top: 3rem;
          color: var(--muted);
          font-size: 0.8rem;
        }
      `}</style>

      <section className="contact-section" id="contact">
        <motion.div variants={container} initial="hidden" whileInView="show">

          {/* HEADER */}
          <div className="contact-header">
            <SectionLabel text="Contact" />

            <motion.h2 style={sectionTitle} className="contact-heading" variants={fadeUp}>
              Let's Build Something
            </motion.h2>

            <motion.p className="contact-desc" variants={fadeUp}>
              Available for full-time roles and exciting fintech and enterprise projects. Let's connect and build scalable, high-performance systems together.
            </motion.p>
          </div>

          {/* CENTERED GRID */}
          <div className="contact-grid-wrapper">
            <motion.div className="contact-grid" variants={container}>
              {items.map((item, i) => (
                <motion.div
                  key={i}
                  ref={(el) => (magnetRefs.current[i] = el)}
                  className="contact-card"
                  variants={fadeUp}
                  onMouseMove={(e) => handleMouseMove(e, i)}
                  onMouseLeave={() => resetMagnet(i)}
                  onClick={() => item.copy && handleCopy(item.value)}
                >
                  <span className="contact-icon">{item.icon}</span>
                  <span className="contact-lbl">{item.label}</span>

                  {item.href ? (
                    <a
                      href={item.href}
                      className={`contact-val${item.copy && copied ? " contact-val--copied" : ""}`}
                      target={item.external ? "_blank" : undefined}
                      rel={item.external ? "noopener noreferrer" : undefined}
                      onClick={(e) => {
                        if (item.copy) {
                          e.preventDefault();
                          handleCopy(item.value);
                        }
                      }}
                    >
                      {item.copy && copied ? "✓ Copied!" : item.value}
                    </a>
                  ) : (
                    <span className="contact-val">{item.value}</span>
                  )}
                </motion.div>
              ))}
            </motion.div>
          </div>

          {/* CTA */}
          <div className="contact-cta-row">
            <motion.a href={`mailto:${contact.email}`} className="contact-cta">
              ✉ Send Email
            </motion.a>
          </div>

          {/* FOOTER */}
          <motion.p className="contact-footer">
            Built with React · Designed to impress · © {new Date().getFullYear()} Akash Chavan
          </motion.p>

        </motion.div>
      </section>
    </>
  );
}
